=== FILE: style.css ===
```css
/* Basic reset */
* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: Impact, 'Arial Black', 'Comic Sans MS', sans-serif;
    background: repeating-radial-gradient(circle at 0 0, #fff, #fff 2px, #f0f0f0 2px, #f0f0f0 4px);
    color: #000;
    line-height: 1.6;
}

/* Navigation */
#navbar {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    background: #000;
    z-index: 1000;
}
#navbar ul {
    list-style: none;
    display: flex;
    justify-content: center;
}
#navbar li {
    margin: 0 1rem;
}
#navbar a {
    display: block;
    padding: 1rem;
    color: #FFD700;
    text-decoration: none;
    font-weight: bold;
}
#navbar a.active {
    background: #FF0000;
    color: #fff;
}

/* Panels */
.panel {
    padding: 4rem 2rem;
    margin-top: 4rem; /* space for fixed nav */
    border: 8px solid #000;
    background: #fff;
    position: relative;
    box-shadow: 4px 4px 0 #000;
    max-width: 800px;
    margin-left: auto;
    margin-right: auto;
}
.panel h2 {
    text-align: center;
    margin-bottom: 1rem;
    color: #1E90FF;
}

/* Speech bubble */
.speech-bubble {
    position: relative;
    background: #fff;
    border: 4px solid #000;
    border-radius: 10px;
    padding: 1rem;
    margin: 1rem auto;
    max-width: 90%;
}
.speech-bubble::after {
    content: '';
    position: absolute;
    bottom: -20px;
    left: 50%;
    transform: translateX(-50%);
    width: 0;
    height: 0;
    border: 20px solid transparent;
    border-top-color: #fff;
    border-bottom: 0;
    border-left: 0;
}
.speech-bubble::before {
    content: '';
    position: absolute;
    bottom: -24px;
    left: 50%;
    transform: translateX(-50%);
    width: 0;
    height: 0;
    border: 24px solid transparent;
    border-top-color: #000;
    border-bottom: 0;
    border-left: 0;
}

/* Responsive */
@media (max-width: 600px) {
    .panel {
        margin-top: 5rem;
    }
    #navbar ul {
        flex-direction: column;
    }
    #navbar li {
        margin: 0;
    }
}
```
